{"method_body":"{
  hottest := 1;
  var idx := 1;
  while idx < inputs.Length
    invariant 1 <= idx <= inputs.Length
    invariant 1 <= hottest <= idx
    invariant forall i :: 0 <= i < idx ==> inputs[hottest - 1] >= inputs[i]
    decreases inputs.Length - idx
  {
    if inputs[idx] > inputs[hottest - 1] {
      hottest := idx + 1;
    }
    idx := idx + 1;
  }
}"}

